1	#!/usr/bin/env node
2	// Markdown SSG — CLI Entry Point
3	// Commands: md-ssg build <src> <out> [--template <path>] [--css <path>]
4	//           md-ssg serve <src> <out> [--port <port>]
5	
6	import { readFileSync, writeFileSync, existsSync, mkdirSync, readdirSync } from 'node:fs';
7	import { join, relative, resolve } from 'node:path';
8	import { tokenize } from './lexer.js';
9	import { buildAST } from './ast.js';
10	import { renderToHTML } from './renderer.js';
11	import { renderTemplate, DEFAULT_TEMPLATE } from './template.js';
12	
13	// =============================================================================
14	// CLI Args Parsing
15	// =============================================================================
16	
17	interface BuildOptions {
18	  src: string;
19	  out: string;
20	  template?: string;
21	  css?: string;
22	}
23	
24	interface ServeOptions extends BuildOptions {
25	  port: number;
26	}
27	
28	type CliResult =
29	  | { command: 'build'; opts: BuildOptions }
30	  | { command: 'serve'; opts: ServeOptions }
31	  | null;
32	
33	function parseArgs(): CliResult {
34	  const args = process.argv.slice(2);
35	  if (args.length < 1) return null;
36	
37	  const command = args[0];
38	  if (command !== 'build' && command !== 'serve') return null;
39	
40	  if (args.length < 3) return null;
41	
42	  const src = resolve(args[1]);
43	  const out = resolve(args[2]);
44	
45	  let templatePath: string | undefined;
46	  let cssPath: string | undefined;
47	  let port = 3000;
48	
49	  for (let i = 3; i < args.length; i++) {
50	    switch (args[i]) {
51	      case '--template':
52	        templatePath = args[++i];
53	        break;
54	      case '--css':
55	        cssPath = args[++i];
56	        break;
57	      case '--port':
58	        port = parseInt(args[++i], 10);
59	        if (Number.isNaN(port) || port < 1 || port > 65535) port = 3000;
60	        break;
61	    }
62	  }
63	
64	  const base: BuildOptions = { src, out, template: templatePath, css: cssPath };
65	
66	  if (command === 'build') {
67	    return { command: 'build', opts: base };
68	  }
69	
70	  return { command: 'serve', opts: { ...base, port } };
71	}
72	
73	// =============================================================================
74	// Build Pipeline
75	// =============================================================================
76	
77	interface FileResult {
78	  file: string;
79	  status: 'ok' | 'skipped' | 'error';
80	  error?: string;
81	}
82	
83	/**
84	 * Build all .md files from source directory to output directory.
85	 * Returns the list of processed files.
86	 */
87	export function buildAll(
88	  srcDir: string,
89	  outDir: string,
90	  templateStr: string = DEFAULT_TEMPLATE,
91	  cssContent: string = '',
92	): FileResult[] {
93	  if (!existsSync(srcDir)) {
94	    throw new Error(`Source directory not found: ${srcDir}`);
95	  }
96	
97	  const mdFiles = collectMdFiles(srcDir);
98	  const results: FileResult[] = [];
99	
100	  for (const mdPath of mdFiles) {
101	    const relPath = relative(srcDir, mdPath);
102	    const htmlRelPath = relPath.replace(/\.md$/i, '.html');
103	    const outPath = join(outDir, htmlRelPath);
104	
105	    try {
106	      const content = readFileSync(mdPath, 'utf-8');
107	      const tokens = tokenize(content);
108	      const ast = buildAST(tokens);
109	      const htmlContent = renderToHTML(ast);
110	
111	      // Ensure output directory exists
112	      const outDirPath = join(outDir, dirname(htmlRelPath));
113	      if (!existsSync(outDirPath)) {
114	        mkdirSync(outDirPath, { recursive: true });
115	      }
116	
117	      // Build title from filename (without .md extension)
118	      const title = relativePathBasename(relPath).replace(/\.md$/i, '');
119	
120	      const finalHtml = renderTemplate(templateStr, {
121	        title,
122	        style: cssContent,
123	        content: htmlContent,
124	      });
125	
126	      writeFileSync(outPath, finalHtml, 'utf-8');
127	      results.push({ file: htmlRelPath, status: 'ok' });
128	    } catch (err) {
129	      const message = err instanceof Error ? err.message : String(err);
130	      results.push({ file: relPath, status: 'error', error: message });
131	    }
132	  }
133	
134	  return results;
135	}
136	
137	// =============================================================================
138	// Helpers
139	// =============================================================================
140	
141	/**
142	 * Recursively collect all .md files from a directory.
143	 */
144	function collectMdFiles(dir: string): string[] {
145	  const files: string[] = [];
146	  const entries = readdirSync(dir, { withFileTypes: true });
147	  for (const entry of entries) {
148	    const fullPath = join(dir, entry.name);
149	    if (entry.isDirectory()) {
150	      files.push(...collectMdFiles(fullPath));
151	    } else if (entry.isFile() && entry.name.toLowerCase().endsWith('.md')) {
152	      files.push(fullPath);
153	    }
154	  }
155	  return files;
156	}
157	
158	/**
159	 * Directory name from a relative path string (works cross-platform).
160	 */
161	function dirname(p: string): string {
162	  const idx = p.lastIndexOf('/');
163	  const bsIdx = p.lastIndexOf('\\');
164	  const sep = Math.max(idx, bsIdx);
165	  return sep === -1 ? '.' : p.slice(0, sep) || '.';
166	}
167	
168	/**
169	 * Basename of a path (works cross-platform).
170	 */
171	function relativePathBasename(p: string): string {
172	  const idx = p.lastIndexOf('/');
173	  const bsIdx = p.lastIndexOf('\\');
174	  const sep = Math.max(idx, bsIdx);
175	  return sep === -1 ? p : p.slice(sep + 1);
176	}
177	
178	// =============================================================================
179	// Main
180	// =============================================================================
181	
182	async function main(): Promise<void> {
183	  const parsed = parseArgs();
184	  if (!parsed) {
185	    console.error('Usage:');
186	    console.error('  md-ssg build <src> <out> [--template <path>] [--css <path>]');
187	    console.error('  md-ssg serve <src> <out> [--port <port>]');
188	    process.exit(1);
189	  }
190	
191	  if (parsed.command === 'build') {
192	    const { src, out, template: templatePath, css: cssPath } = parsed.opts;
193	
194	    let templateStr = DEFAULT_TEMPLATE;
195	    if (templatePath) {
196	      try {
197	        templateStr = readFileSync(resolve(templatePath), 'utf-8');
198	      } catch {
199	        console.error(`Error: Cannot read template file: ${templatePath}`);
200	        process.exit(1);
201	      }
202	    }
203	
204	    let cssContent = '';
205	    if (cssPath) {
206	      try {
207	        cssContent = readFileSync(resolve(cssPath), 'utf-8');
208	      } catch {
209	        console.error(`Error: Cannot read CSS file: ${cssPath}`);
210	        process.exit(1);
211	      }
212	    }
213	
214	    console.log(`Building from ${src} -> ${out}`);
215	    const results = buildAll(src, out, templateStr, cssContent);
216	
217	    let okCount = 0;
218	    let errorCount = 0;
219	    for (const r of results) {
220	      const prefix = r.status === 'ok' ? '  ok' : '  FAIL';
221	      const suffix = r.error ? ` - ${r.error}` : '';
222	      console.log(`${prefix} ${r.file}${suffix}`);
223	      if (r.status === 'ok') okCount++;
224	      else errorCount++;
225	    }
226	
227	    console.log(`\nDone: ${okCount} built, ${errorCount} errors`);
228	    if (errorCount > 0) process.exit(1);
229	  } else {
230	    // serve command
231	    const { src, out, port, template: templatePath, css: cssPath } = parsed.opts;
